import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import DataLoader, Dataset
from torchvision import transforms
from torchvision.models import resnet18, ResNet18_Weights
import requests
from io import BytesIO
from PIL import Image
import os

# --- Configuration ---
MODEL_URL = "https://download.pytorch.org/models/resnet18-f37072fd.pth" # Example ResNet18 URL
LOCAL_MODEL_PATH = "resnet18_pretrained.pth"
NUM_CLASSES = 10 # Example: Number of classes in your custom dataset
BATCH_SIZE = 32
LEARNING_RATE = 0.001
NUM_EPOCHS = 5
DEVICE = torch.device("cuda" if torch.cuda.is_available() else "cpu")

# --- 1. Download Pretrained Model ---
def download_model(url, save_path):
    if os.path.exists(save_path):
        print(f"Model already exists at {save_path}. Skipping download.")
        return

    print(f"Downloading model from {url} to {save_path}...")
    try:
        response = requests.get(url, stream=True)
        response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)
        with open(save_path, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)
        print("Download complete.")
    except requests.exceptions.RequestException as e:
        print(f"Error downloading model: {e}")
        exit()

# --- 2. Custom Dataset (Example) ---
# Replace this with your actual custom dataset loading logic
class CustomDataset(Dataset):
    def __init__(self, num_samples=100, transform=None):
        self.num_samples = num_samples
        self.transform = transform
        # Simulate some dummy data
        self.data = [Image.new('RGB', (224, 224), color = (i*20 % 255, (i*30+50) % 255, (i*40+100) % 255)) for i in range(num_samples)]
        self.labels = [i % NUM_CLASSES for i in range(num_samples)]

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        image = self.data[idx]
        label = self.labels[idx]

        if self.transform:
            image = self.transform(image)
        return image, label

# --- 3. Model Loading and Fine-tuning ---
def fine_tune_model():
    # Download the model checkpoint
    download_model(MODEL_URL, LOCAL_MODEL_PATH)

    # Load a pre-trained ResNet18 model
    # We'll use the torchvision.models API for convenience,
    # but demonstrate loading a custom checkpoint if needed.

    # Option A: Load a model from torchvision.models and then load state_dict
    # This is often preferred as it ensures the model architecture is correct.
    model = resnet18(weights=None) # Initialize model with default weights (or no weights)
    print(f"Loading state_dict from {LOCAL_MODEL_PATH}...")
    try:
        # Load the state_dict from the downloaded file
        # map_location ensures it loads correctly regardless of GPU availability
        state_dict = torch.load(LOCAL_MODEL_PATH, map_location=DEVICE)
        model.load_state_dict(state_dict)
        print("Model state_dict loaded successfully.")
    except Exception as e:
        print(f"Error loading state_dict: {e}")
        print("Attempting to load using torchvision's default weights instead.")
        model = resnet18(weights=ResNet18_Weights.IMAGENET1K_V1)


    # Freeze all parameters in the network
    # for param in model.parameters():
    #     param.requires_grad = False

    # Replace the final classification layer
    num_ftrs = model.fc.in_features
    model.fc = nn.Linear(num_ftrs, NUM_CLASSES)

    model = model.to(DEVICE)

    # Define loss function and optimizer
    criterion = nn.CrossEntropyLoss()
    # Only optimize parameters that have requires_grad=True (i.e., the new fc layer)
    optimizer = optim.Adam(model.parameters(), lr=LEARNING_RATE)

    # Data transformations
    transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    # Create custom dataset and dataloader
    train_dataset = CustomDataset(num_samples=1000, transform=transform)
    train_loader = DataLoader(train_dataset, batch_size=BATCH_SIZE, shuffle=True)

    print("\nStarting fine-tuning...")
    for epoch in range(NUM_EPOCHS):
        model.train()
        running_loss = 0.0
        for i, (inputs, labels) in enumerate(train_loader):
            inputs, labels = inputs.to(DEVICE), labels.to(DEVICE)

            optimizer.zero_grad()

            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

            running_loss += loss.item()

        print(f"Epoch {epoch+1}/{NUM_EPOCHS}, Loss: {running_loss/len(train_loader):.4f}")

    print("Fine-tuning complete.")

    # --- Optional: Save the fine-tuned model ---
    torch.save(model.state_dict(), "fine_tuned_model.pth")
    print("Fine-tuned model saved to fine_tuned_model.pth")

if __name__ == "__main__":
    fine_tune_model()